INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('d03fe735-c7e8-4094-9f03-efd512ee0d45', 'Trong IELTS Speaking Part 1, mục đích chính của các câu hỏi về bản thân (Hometown, Work/Study, Accommodation) là gì?', 'multiple_choice', '["Đánh giá vốn từ vựng học thuật chuyên sâu của bạn.","Giúp bạn thư giãn, làm nóng (warm-up) bằng các chủ đề quen thuộc và kiểm tra khả năng giao tiếp trôi chảy hàng ngày.","Đánh giá khả năng tranh luận phản biện của bạn.","Kiểm tra kiến thức địa lý và xã hội học của bạn."]', 'Giúp bạn thư giãn, làm nóng (warm-up) bằng các chủ đề quen thuộc và kiểm tra khả năng giao tiếp trôi chảy hàng ngày.', 'Part 1 đóng vai trò như một cuộc phỏng vấn làm quen nhỏ. Giám khảo không mong đợi những triết lý cao siêu mà muốn thấy sự tự nhiên và trôi chảy (Fluency) của bạn.'),
('d03fe735-c7e8-4094-9f03-efd512ee0d45', 'Độ dài lý tưởng nhất cho một câu trả lời trong IELTS Speaking Part 1 là bao nhiêu?', 'multiple_choice', '["Chỉ 1 từ (Ví dụ: Yes / No).","Khoảng 2-3 câu (Trả lời trực tiếp vào trọng tâm, sau đó mở rộng bằng 1 lý do hoặc 1 chi tiết nhỏ).","Càng dài càng tốt, nói liên tục cho đến khi giám khảo ngắt lời.","Khoảng 5 phút cho mỗi câu hỏi."]', 'Khoảng 2-3 câu (Trả lời trực tiếp vào trọng tâm, sau đó mở rộng bằng 1 lý do hoặc 1 chi tiết nhỏ).', 'Trả lời quá ngắn sẽ không đủ dữ liệu chấm điểm (under-developed), trả lời quá dài sẽ lan man (off-topic) và chiếm mất thời gian của các câu hỏi khác.'),
('d03fe735-c7e8-4094-9f03-efd512ee0d45', 'Khi giám khảo hỏi ''Do you work or are you a student?'', bạn KHÔNG NÊN mở đầu câu trả lời bằng cách nào?', 'multiple_choice', '["Well, currently I''m a senior at...","I''m working as an accountant for...","As you can see in my resume...","At the moment, I''m pursuing a degree in..."]', 'As you can see in my resume...', 'Giám khảo IELTS Speaking hoàn toàn không biết bạn là ai và không có hồ sơ của bạn. Bạn phải trả lời như thể đang nói chuyện với một người mới quen.'),
('5289bd94-c56e-4e9f-808f-a1e82c7c37a4', 'Khi được hỏi về một chủ đề quen thuộc nhưng bạn chưa bao giờ làm (ví dụ: ''Do you like gardening?''), bạn nên làm gì?', 'multiple_choice', '["Nói dối rằng bạn rất thích và bịa ra một câu chuyện.","Im lặng vì không biết nói gì.","Thành thật nói ''Không'', sau đó giải thích lý do tại sao hoặc nói về một sở thích khác thay thế.","Hỏi ngược lại giám khảo xem họ có thích không."]', 'Thành thật nói ''Không'', sau đó giải thích lý do tại sao hoặc nói về một sở thích khác thay thế.', 'IELTS là bài thi ngôn ngữ, không phải bài kiểm tra sự thật. Việc nói ''To be honest, I don''t have a green thumb because...'' là một cách trả lời cực kỳ tự nhiên và được điểm cao.'),
('5289bd94-c56e-4e9f-808f-a1e82c7c37a4', 'Cấu trúc ''Used to'' rất hữu ích trong Part 1 để làm gì?', 'multiple_choice', '["Dự đoán tương lai.","Kéo dài thời gian suy nghĩ.","So sánh thói quen/sở thích trong quá khứ với hiện tại để làm câu trả lời phong phú hơn.","Hỏi đường."]', 'So sánh thói quen/sở thích trong quá khứ với hiện tại để làm câu trả lời phong phú hơn.', 'Việc mở rộng thời gian (Time expansion) là kỹ thuật xuất sắc. Ví dụ: ''I used to hate vegetables as a kid, but now I eat them daily''.'),
('5289bd94-c56e-4e9f-808f-a1e82c7c37a4', 'Để thay thế cho từ ''I like'' lặp đi lặp lại quá nhiều lần trong Part 1, bạn có thể dùng cụm từ nào?', 'multiple_choice', '["I am angry at...","I am a big fan of... / I''m really into...","I ignore...","I force myself to..."]', 'I am a big fan of... / I''m really into...', 'Sử dụng đa dạng các cụm từ thể hiện sở thích (I''m keen on, I''m passionate about) giúp tăng điểm tiêu chí Lexical Resource.'),
('cf4eb31c-8d0c-4cbf-bb2b-8e3cc74d3a26', 'Trong Speaking Part 2 (Mô tả người), yếu tố nào quan trọng hơn việc chỉ liệt kê ngoại hình (tóc, mắt, chiều cao)?', 'multiple_choice', '["Nói chính xác tuổi của họ.","Kể về thu nhập của họ.","Miêu tả tính cách, phẩm chất và kể một kỷ niệm hoặc câu chuyện nhỏ giải thích tại sao họ lại có ảnh hưởng đến bạn.","Đọc tiểu sử của họ trên Wikipedia."]', 'Miêu tả tính cách, phẩm chất và kể một kỷ niệm hoặc câu chuyện nhỏ giải thích tại sao họ lại có ảnh hưởng đến bạn.', 'Miêu tả ngoại hình rất dễ cạn ý tưởng. Việc kể một câu chuyện (Anecdote) chứng minh tính cách của họ sẽ giúp bạn dễ dàng nói trôi chảy suốt 2 phút.'),
('cf4eb31c-8d0c-4cbf-bb2b-8e3cc74d3a26', 'Bạn có 1 phút chuẩn bị (Take notes) trước khi nói Part 2. Cách ghi chú nào hiệu quả nhất?', 'multiple_choice', '["Viết hoàn chỉnh từng câu từng chữ rồi đọc lại.","Không viết gì cả, chỉ nhắm mắt suy nghĩ.","Chỉ viết các từ khóa (Keywords), cụm từ vựng (Collocations) và các ý chính theo cấu trúc câu hỏi gợi ý.","Vẽ chân dung người đó ra giấy."]', 'Chỉ viết các từ khóa (Keywords), cụm từ vựng (Collocations) và các ý chính theo cấu trúc câu hỏi gợi ý.', 'Bạn không bao giờ có đủ 1 phút để viết thành câu. Viết từ khóa giúp bạn có ''điểm neo'' để nhìn vào khi lỡ quên ý, giữ được sự giao tiếp bằng mắt (Eye-contact).'),
('cf4eb31c-8d0c-4cbf-bb2b-8e3cc74d3a26', 'Để miêu tả một người rất dễ gần và thân thiện, bạn dùng Idiom nào?', 'multiple_choice', '["A tough cookie.","A pain in the neck.","Down-to-earth.","A dark horse."]', 'Down-to-earth.', '''Down-to-earth'' là thành ngữ rất tự nhiên chỉ một người thực tế, giản dị, thân thiện và không hề kiêu ngạo.'),
('687df7f4-332c-4769-ad2a-eb06ca57bd37', 'Khi mô tả một Sự kiện hoặc Địa điểm (Event & Place) trong Part 2, việc sử dụng các ''Sensory details'' (Chi tiết giác quan) mang lại lợi ích gì?', 'multiple_choice', '["Làm giám khảo khó hiểu hơn.","Giúp bức tranh miêu tả trở nên sống động và chân thực hơn (ví dụ: mùi thức ăn, tiếng ồn ào, màu sắc rực rỡ).","Làm tốn thời gian vô ích.","Chứng minh bạn không nói dối."]', 'Giúp bức tranh miêu tả trở nên sống động và chân thực hơn (ví dụ: mùi thức ăn, tiếng ồn ào, màu sắc rực rỡ).', 'Việc sử dụng tính từ miêu tả chi tiết (picturesque, deafening, mouth-watering) đẩy điểm Vocabulary của bạn lên mức 7.0+ dễ dàng.'),
('687df7f4-332c-4769-ad2a-eb06ca57bd37', 'Nếu bạn đang nói Part 2 mà bị ''bí ý tưởng'' (Run out of ideas) trước khi hết 2 phút, bạn nên sử dụng chiến thuật nào?', 'multiple_choice', '["Nói ''I''m done'' và im lặng.","Lặp lại chính xác những gì vừa nói.","Chuyển hướng (Pivot) sang việc nói về cảm xúc tương lai: ''If I have a chance, I would definitely go there again because...''.","Hỏi giám khảo xem họ đã đi đến đó chưa."]', 'Chuyển hướng (Pivot) sang việc nói về cảm xúc tương lai: ''If I have a chance, I would definitely go there again because...''.', 'Kéo dài bài nói bằng cách thêm một giả định tương lai (Future conditional) là chiếc phao cứu sinh hoàn hảo để lấp đầy 15-20 giây còn thiếu.'),
('687df7f4-332c-4769-ad2a-eb06ca57bd37', 'Từ vựng nào thay thế tốt nhất cho từ ''beautiful'' khi miêu tả một phong cảnh thiên nhiên hùng vĩ?', 'multiple_choice', '["Nice","Breathtaking / Spectacular","Okay","Normal"]', 'Breathtaking / Spectacular', '''Breathtaking'' (đẹp đến nín thở) là tính từ mô tả nâng cao (Advanced adjectives) cực kỳ ghi điểm trong chủ đề Places.'),
('08367e36-8aa6-425c-88a1-87b84fdcfd45', 'Trong chủ đề ''Mô tả một trải nghiệm'' (Describe an experience), lỗi ngữ pháp nghiêm trọng nhất khiến thí sinh bị trừ điểm nặng là gì?', 'multiple_choice', '["Không dùng thì Tương lai.","Không sử dụng câu bị động.","Sử dụng sai các Thì quá khứ (Ví dụ: dùng thì Hiện tại đơn để kể về một chuyến đi năm ngoái).","Không dùng câu điều kiện."]', 'Sử dụng sai các Thì quá khứ (Ví dụ: dùng thì Hiện tại đơn để kể về một chuyến đi năm ngoái).', 'Đã kể lại trải nghiệm (Experience) thì 90% câu chuyện nằm ở Quá khứ. Việc kiểm soát tốt Past Simple, Past Continuous và Past Perfect là tiêu chí chấm điểm GRA cốt lõi.'),
('08367e36-8aa6-425c-88a1-87b84fdcfd45', 'Để bài nói Part 2 có tính liên kết chặt chẽ (Coherence), bạn nên sử dụng các từ nối (Signpost words) như thế nào?', 'multiple_choice', '["Không dùng từ nối nào cả.","Dùng thật nhiều ''and'' và ''so''.","Dùng các từ chuyển ý tự nhiên như ''Initially...'', ''Then...'', ''Unexpectedly...'', ''Looking back now...''.","Dùng các từ học thuật cứng nhắc như ''Furthermore'', ''Moreover''."]', 'Dùng các từ chuyển ý tự nhiên như ''Initially...'', ''Then...'', ''Unexpectedly...'', ''Looking back now...''.', 'Văn nói (Spoken English) chuộng sự tự nhiên. Các từ nối như ''Moreover'', ''Furthermore'' phù hợp cho Writing, trong khi Speaking ưu tiên ''To begin with'', ''Another thing is'', ''Eventually''.'),
('08367e36-8aa6-425c-88a1-87b84fdcfd45', 'Câu hỏi cuối cùng trên thẻ gợi ý (Cue card) thường là ''Explain how you felt about it''. Tại sao phần này lại quan trọng nhất?', 'multiple_choice', '["Vì nó là câu hỏi duy nhất có điểm.","Vì đây là phần cho phép bạn sử dụng đa dạng các từ vựng diễn tả cảm xúc và đưa ra phản tư (reflection) sâu sắc, dễ mở rộng ý nhất.","Vì nó là câu hỏi dễ nhất.","Vì nó giúp bạn đánh giá giám khảo."]', 'Vì đây là phần cho phép bạn sử dụng đa dạng các từ vựng diễn tả cảm xúc và đưa ra phản tư (reflection) sâu sắc, dễ mở rộng ý nhất.', 'Cảm xúc là thứ không có giới hạn. Thay vì miêu tả sự vật (rất dễ hết ý), việc nói về bài học rút ra, sự thay đổi trong tâm trí sẽ giúp bạn nói trơn tru đến khi hết giờ.'),
('34165735-1f4a-4c12-be29-2eb952d36383', 'Sự khác biệt cốt lõi giữa Speaking Part 1 và Part 3 là gì?', 'multiple_choice', '["Part 3 bạn phải tự nói một mình không có giám khảo.","Part 1 hỏi về thông tin cá nhân; Part 3 yêu cầu thảo luận về các vấn đề xã hội trừu tượng mang tính vĩ mô (không dùng trải nghiệm cá nhân làm trọng tâm).","Part 3 yêu cầu nói nhanh gấp đôi.","Part 1 chấm điểm từ vựng, Part 3 chấm điểm ngữ pháp."]', 'Part 1 hỏi về thông tin cá nhân; Part 3 yêu cầu thảo luận về các vấn đề xã hội trừu tượng mang tính vĩ mô (không dùng trải nghiệm cá nhân làm trọng tâm).', 'Trong Part 3, bạn không nên nói ''Tôi thích...'' mà phải nói ''Nhiều người trong xã hội hiện đại tin rằng...''. Bạn đang đóng vai trò một nhà phân tích xã hội.'),
('34165735-1f4a-4c12-be29-2eb952d36383', 'Cấu trúc trả lời nào là tối ưu nhất để giải quyết một câu hỏi phức tạp trong Part 3 (ví dụ: So sánh, Phân tích nguyên nhân)?', 'multiple_choice', '["Trả lời 1 từ rồi cười.","Cấu trúc A.R.E.A (Answer - Reason - Example - Alternative/Result).","Cấu trúc chép lại câu hỏi của giám khảo.","Cấu trúc kể chuyện cổ tích."]', 'Cấu trúc A.R.E.A (Answer - Reason - Example - Alternative/Result).', 'Đưa ra câu trả lời trực diện -> Giải thích tại sao -> Nêu ví dụ xã hội minh họa -> Rút ra kết luận. Đây là format của một đoạn văn Argumentative thu nhỏ.'),
('34165735-1f4a-4c12-be29-2eb952d36383', 'Nếu giám khảo đặt một câu hỏi Part 3 quá khó và bạn cần vài giây để suy nghĩ, bạn nên nói gì?', 'multiple_choice', '["Uhhh... I don''t know.","That''s a very interesting question. I''ve never really thought about it before, but I suppose...","Skip this question please.","Im lặng hoàn toàn nhìn chằm chằm giám khảo."]', 'That''s a very interesting question. I''ve never really thought about it before, but I suppose...', 'Kỹ thuật ''Buying time'' (câu giờ) bằng ngôn ngữ tự nhiên không những không bị trừ điểm mà còn thể hiện sự trôi chảy và khả năng làm chủ cuộc giao tiếp của bạn.');